class SecureFormatter(logging.Formatter):
    """A log formatter that sanitizes sensitive data from log messages."""

    # Patterns for sensitive data that should be redacted
    SENSITIVE_PATTERNS = [
        (re.compile(r'(?i)(password|passwd|pwd)\s*[=:]\s*\S+'), r'\1=***REDACTED***'),
        (re.compile(r'(?i)(token|api_key|apikey|secret|auth)\s*[=:]\s*\S+'), r'\1=***REDACTED***'),
        (re.compile(r'(?i)(authorization)\s*[=:]\s*\S+'), r'\1=***REDACTED***'),
        (re.compile(r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b'), '***EMAIL_REDACTED***'),
        (re.compile(r'\b\d{3}-\d{2}-\d{4}\b'), '***SSN_REDACTED***'),
        (re.compile(r'\b(?:\d{4}[-\s]?){3}\d{4}\b'), '***CC_REDACTED***'),
    ]

    def format(self, record: logging.LogRecord) -> str:
        message = super().format(record)
        return self._sanitize(message)

    def _sanitize(self, message: str) -> str:
        """Remove sensitive data patterns from log messages."""
        for pattern, replacement in self.SENSITIVE_PATTERNS:
            message = pattern.sub(replacement, message)
        return message


class SecureRotatingFileHandler(logging.handlers.RotatingFileHandler):
    """A rotating file handler that sets secure file permissions on rotated files."""

    def __init__(self, *args, file_permissions: int = None, **kwargs):
        self.file_permissions = file_permissions or (stat.S_IRUSR | stat.S_IWUSR)
        super().__init__(*args, **kwargs)
        # Set permissions on the initial file
